27	const PROCESSING_FEE = 5;
28	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
29	const BLOCK_OF_THREE_DISCOUNT = 15;
30	
31	const BASE_PREMIUM: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	  moonstone: 25,
38	};
39	
40	const blockOfThreeDiscount = (alikeComponentCount: number): number =>
41	  alikeComponentCount === 3 ? BLOCK_OF_THREE_DISCOUNT : 0;
42	
43	const COMPONENT_TYPES = ["rune", "moonstone"];
44	
45	const countItemsOfType = (items: Item[], type: string): number =>
46	  items.filter((item) => item.type === type).length;
47	
48	const CURSE_SURCHARGE_RATE = 0.5;
49	const LOYALTY_DISCOUNT_RATE = 0.2;
50	const LOYALTY_YEARS_THRESHOLD = 2;
51	
52	const sumItemSpecificSurcharges = (items: Item[]): number =>
53	  items.reduce((sum, item) => {
54	    const base = BASE_PREMIUM[item.type];
55	    const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
56	    return sum + curse;
57	  }, 0);
58	
59	const calculateBasePremium = (items: Item[]): number => {
60	  const subtotal = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
61	  const totalDiscount = COMPONENT_TYPES.reduce(
62	    (sum, type) => sum + blockOfThreeDiscount(countItemsOfType(items, type)),
63	    0,
64	  );
65	  return subtotal - totalDiscount;
66	};
67	
68	const quote = (step: QuoteStep, customer: Scenario["customer"]): QuoteResult => {
69	  const basePremium = calculateBasePremium(step.items);
70	  const itemSurcharges = sumItemSpecificSurcharges(step.items);
71	  const firstContractSurcharge = basePremium * FIRST_CONTRACT_SURCHARGE_RATE;
72	  const loyaltyDiscount =
73	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
74	  const premium = Math.ceil(
75	    basePremium + itemSurcharges + firstContractSurcharge - loyaltyDiscount + PROCESSING_FEE,
76	  );
77	  return { premium };
78	};
79	
80	export const runScenario = (scenario: Scenario): ScenarioResult => {
81	  const results = scenario.steps.map((step) => quote(step, scenario.customer));
82	  return { results };
83	};
